{
  "grammar": [
    {
      "pattern": "可以 + [action] + [object] + 嗎？",
      "structure": ["可以", "action", "object", "嗎"],
      "explanation_en": "Use '可以...嗎？' to politely ask for permission or request an action. It is a standard polite form in Taiwan.",
      "title": "Polite Request with 可以...嗎？",
      "meaning": "May I...? / Can I...?",
      "when_to_use": ["When asking for permission to do something", "When requesting an action from someone"],
      "when_not_to_use": ["When making a direct command or demand", "When speaking to close friends in very casual settings"],
      "pragmatic_notes": "In Taiwan, using '可以...嗎？' is considered polite and appropriate in shops and cafés. It softens the request and shows respect.",
      "word_order_notes": "The structure is: 可以 + verb + object + 嗎. Do not place 嗎 before the verb.",
      "english_contrast": "English uses 'Can I...?' or 'May I...?' at the beginning. Chinese places 可以 before the verb and 嗎 at the end.",
      "korean_contrast": "Korean uses '~을/를 해도 될까요?' which is similar in politeness but placed at the end. Chinese uses a fixed structure with 可以.",
      "negative_examples": [
        {
          "text": "可以嗎我喝水？",
          "error": "Word order is incorrect. 可以 must come before the verb, and 嗎 must be at the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我喝水可以嗎？",
          "error": "While understandable, this is less natural. Standard polite request uses '可以 + verb + object + 嗎'."
        }
      ],
      "transformation_drills": ["Change '我要一杯水' to a polite request using 可以...嗎？"],
      "production_drills": ["Ask for permission to sit here using 可以...嗎？"],
      "common_error_patterns": ["Placing 嗎 before the verb", "Omitting 可以 and using a direct command"],
      "repair_feedback": {
        "word_order": "Remember: 可以 + verb + object + 嗎",
        "politeness": "Using 可以...嗎？ is polite; avoid direct commands like '給我水'.",
        "vocabulary": "Use appropriate verbs like 喝, 吃, 坐, 看."
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' to express what you want in a polite and indirect way. It is softer than '要' and common in service settings.",
      "title": "Expressing Wants with 想要",
      "meaning": "I would like...",
      "when_to_use": ["When ordering food or drinks", "When expressing a desire politely"],
      "when_not_to_use": ["When making a direct demand", "When the context requires a request for permission"],
      "pragmatic_notes": "In Taiwan, '想要' is preferred over '要' in polite conversation. It shows consideration and is less assertive.",
      "word_order_notes": "The structure is: 想要 + noun phrase. Do not add 嗎 after 想要; it is a statement, not a question.",
      "english_contrast": "English uses 'I would like...' which is similar. Chinese uses '想要' directly before the object.",
      "korean_contrast": "Korean uses '~을/를 원합니다' which is more formal. '想要' is less formal but still polite.",
      "negative_examples": [
        {
          "text": "想要嗎一杯咖啡？",
          "error": "Incorrect word order. 想要 is not used in questions; use 可以...嗎？ instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我要一杯咖啡。",
          "error": "While correct, '要' is more direct and less polite than '想要' in service contexts."
        }
      ],
      "transformation_drills": ["Change '我要一杯紅茶' to a more polite form using 想要"],
      "production_drills": ["Order a drink using 想要 at a café"],
      "common_error_patterns": ["Using 想要 in questions", "Using 要 instead of 想要 in polite contexts"],
      "repair_feedback": {
        "word_order": "Use 想要 + object, not 想要 + 嗎",
        "politeness": "Use 想要 instead of 要 to sound more polite",
        "vocabulary": "Use object nouns like 咖啡, 茶, 水"
      }
    },
    {
      "pattern": "不好意思，[request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Start a polite request with '不好意思' to get attention or apologize for the interruption. It is a common softener in Taiwan.",
      "title": "Polite Softener with 不好意思",
      "meaning": "Excuse me, ... / Sorry to bother, ...",
      "when_to_use": ["When starting a request in a shop or café", "When you need to get someone's attention"],
      "when_not_to_use": ["When apologizing for a mistake (use 對不起 instead)", "In very formal written requests"],
      "pragmatic_notes": "In Taiwan, '不好意思' is extremely common in daily interactions. It shows humility and politeness, especially when making a request.",
      "word_order_notes": "Place '不好意思' at the beginning of the sentence, followed by the request. Do not put it in the middle or end.",
      "english_contrast": "English uses 'Excuse me' or 'Sorry' at the beginning. Chinese uses '不好意思' similarly.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다' which are more formal. '不好意思' is less formal but very common.",
      "negative_examples": [
        {
          "text": "我想要一杯水不好意思。",
          "error": "Incorrect word order. 不好意思 should come at the beginning, not the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思，可以給我菜單嗎？",
          "error": "This is actually correct! No error here."
        }
      ],
      "transformation_drills": ["Add 不好意思 to the beginning of '可以給我菜單嗎？'"],
      "production_drills": ["Use 不好意思 to ask for a bag at a shop"],
      "common_error_patterns": ["Placing 不好意思 at the end", "Using 對不起 instead of 不好意思 for requests"],
      "repair_feedback": {
        "word_order": "Put 不好意思 at the start of the sentence",
        "politeness": "Using 不好意思 makes the request more polite and natural",
        "vocabulary": "Use 不好意思 for requests, not 對不起"
      }
    }
  ]
}
